function Chip({
  active,
  icon,
  label,
  text,
  onPress,
  t,
  wide,
}: {
  active?: boolean;
  icon?: IconName;
  label?: StreamTextKey;
  text?: string;
  onPress: () => void;
  t: (key: StreamTextKey) => string;
  wide?: boolean;
}) {
  const chipLabel = text ?? (label ? t(label) : "");

  return (
    <Pressable
      onPress={onPress}
      hitSlop={{ top: 6, bottom: 6, left: 4, right: 4 }}
      style={[styles.chip, wide && styles.wideChip, active && styles.chipActive]}
      accessibilityRole="button"
      accessibilityState={{ selected: Boolean(active) }}
      accessibilityLabel={chipLabel}
    >
      {icon ? <Ionicons name={icon} size={14} color={active ? "#09070D" : "#EDE8F4"} /> : null}
      <Text style={[styles.chipText, active && styles.chipTextActive]} numberOfLines={1}>
        {chipLabel}
      </Text>
    </Pressable>
  );
}

function BottomTabs({
  active,
  setActive,
  t,
  bottom,
  screenWidth,
}: {
  active: Tab;
  setActive: (tab: Tab) => void;
  t: (key: StreamTextKey) => string;
  bottom: number;
  screenWidth: number;
}) {
  const compactTabs = screenWidth < 390;
  const veryCompactTabs = screenWidth < 340;

  return (
    <View
      pointerEvents="box-none"
      style={[
        styles.bottomTabs,
        compactTabs ? styles.bottomTabsCompact : null,
        veryCompactTabs ? styles.bottomTabsVeryCompact : null,
        { bottom },
      ]}
    >
      {tabs.map((tab) => {
        const selected = active === tab.id;
        const iconSize = veryCompactTabs ? 20 : compactTabs ? 21 : 23;
        return (
          <Pressable
            key={tab.id}
            onPress={() => setActive(tab.id)}
            hitSlop={{ top: 8, bottom: 8, left: 4, right: 4 }}
            style={[
              styles.tab,
              compactTabs ? styles.tabCompact : null,
              veryCompactTabs ? styles.tabVeryCompact : null,
              selected ? styles.tabActive : null,
            ]}
            accessibilityRole="tab"
            accessibilityState={{ selected }}
            accessibilityLabel={t(tab.label)}
          >
            <Ionicons name={tab.icon} size={iconSize} color={selected ? "#F2C75B" : "#77717F"} />
            <Text
              style={[
                styles.tabText,
                compactTabs ? styles.tabTextCompact : null,
                veryCompactTabs ? styles.tabTextVeryCompact : null,
                selected ? styles.tabTextActive : null,
              ]}
              numberOfLines={1}
              adjustsFontSizeToFit={true}
              minimumFontScale={0.82}
            >
              {t(tab.label)}
            </Text>
          </Pressable>
        );
      })}
    </View>
  );
}

function FixedBrandTitle({ t, top, screenWidth }: { t: (key: StreamTextKey) => string; top: number; screenWidth: number }) {
  const compactTitle = screenWidth < 390;
  const veryCompactTitle = screenWidth < 340;

  return (
    <View
      pointerEvents="none"
      style={[
        styles.fixedTitleOnly,
        compactTitle ? styles.fixedTitleOnlyCompact : null,
        veryCompactTitle ? styles.fixedTitleOnlyVeryCompact : null,
        { top },
      ]}
    >
      <Text
        style={[
          styles.title,
          compactTitle ? styles.titleCompact : null,
          veryCompactTitle ? styles.titleVeryCompact : null,
        ]}
        numberOfLines={1}
        adjustsFontSizeToFit={true}
        minimumFontScale={0.86}
      >
        {t("brand")}
      </Text>
    </View>
  );
}

function CountryPickerModal({
  visible,
  selected,
  onSelect,
  onClose,
  t,
  language,
}: {
  visible: boolean;
  selected: StreamCountryCode;
  onSelect: (country: StreamCountryCode) => void;
  onClose: () => void;
  t: (key: StreamTextKey) => string;
  language?: string | null;
}) {
  const [query, setQuery] = useState("");
  const sheetInsets = useSafeAreaInsets();
  const { height: windowHeight } = useWindowDimensions();
  const countrySheetMaxHeight = Math.max(360, Math.min(windowHeight - Math.max(sheetInsets.top + 92, 124), 620));
  const countrySheetBottomPadding = Math.max(sheetInsets.bottom + 16, 24);
  const countries = useMemo(() => searchStreamCountries(query, language), [query, language]);

  return (
    <Modal visible={visible} transparent animationType="fade" onRequestClose={onClose}>
      <Pressable style={styles.modalBackdrop} onPress={onClose}>
        <Pressable
          style={[styles.countrySheet, { maxHeight: countrySheetMaxHeight, paddingBottom: countrySheetBottomPadding }]}
          onPressIn={(event) => event.stopPropagation()}
          onTouchStart={(event) => event.stopPropagation()}
          onPress={(event) => event.stopPropagation()}
        >
          <View style={styles.countryPickerHeader}>
            <Text style={styles.countrySheetTitle}>{t("selectCountry")}</Text>
            <Pressable style={styles.countryPickerCloseButton} onPress={onClose} hitSlop={8} accessibilityRole="button" accessibilityLabel="Закрыть выбор страны">
              <Ionicons name="close-outline" size={20} color="#F6F2FF" />
            </Pressable>
          </View>
          <View style={styles.countrySearch}>
            <Ionicons name="search-outline" size={18} color="#908A99" />
            <TextInput
              value={query}
              onChangeText={setQuery}
              placeholder={t("search")}
              placeholderTextColor="#908A99"
              style={styles.countrySearchInput}
              returnKeyType="search"
              autoCorrect={false}
              autoCapitalize="none"
              blurOnSubmit={false}
            />
          </View>
          <ScrollView
            showsVerticalScrollIndicator={false}
            contentContainerStyle={styles.countryList}
            keyboardShouldPersistTaps="handled"
            nestedScrollEnabled
            overScrollMode="never"
          >
            {countries.map((country) => {
              const active = selected === country.code;
              return (
                <Pressable
                  key={country.code}
                  style={[styles.countryRow, active && styles.countryRowActive]}
                  hitSlop={{ top: 4, bottom: 4, left: 2, right: 2 }}
                  accessibilityRole="button"
                  onPress={() => {
                    onSelect(country.code);
                    onClose();
                  }}
                >
                  <Text style={[styles.countryName, active && styles.countryNameActive]}>
                    {getStreamCountryName(country.code, language)}
                  </Text>
                  {active ? <Ionicons name="checkmark-circle" size={22} color="#F2C75B" /> : null}
                </Pressable>
              );
            })}
          </ScrollView>
        </Pressable>
      </Pressable>
    </Modal>
  );
}

function MainSettingsModal({
  visible,
  country,
  setCountry,
  type,
  setType,
  category,
  setCategory,
  nearby,
  setNearby,
  onClose,
  t,
  language,
}: {
  visible: boolean;
  country: StreamCountryCode;
  setCountry: (country: StreamCountryCode) => void;
  type: FeedType;
  setType: (type: FeedType) => void;
  category: Category;
  setCategory: (category: Category) => void;
  nearby: boolean;
  setNearby: (nearby: boolean) => void;
  onClose: () => void;
  t: (key: StreamTextKey) => string;
  language?: string | null;
}) {
  const [countryPickerOpen, setCountryPickerOpen] = useState(false);

  return (
    <>
      <Modal visible={visible} transparent animationType="fade" onRequestClose={onClose}>
        <Pressable style={styles.modalBackdrop} onPress={onClose}>
          <Pressable
            style={styles.settingsSheet}
            onPressIn={(event) => event.stopPropagation()}
            onTouchStart={(event) => event.stopPropagation()}
            onPress={(event) => event.stopPropagation()}
            onStartShouldSetResponder={() => true}
          >
            <View style={styles.mainSettingsHeader}>
              <View style={styles.mainSettingsHandle} />
              <Text style={styles.countrySheetTitle}>{t("mainSettings")}</Text>
              <Pressable style={styles.mainSettingsCloseButton} onPress={onClose} hitSlop={8} accessibilityRole="button" accessibilityLabel="Закрыть настройки Stream">
                <Ionicons name="close-outline" size={20} color="#F6F2FF" />
              </Pressable>
            </View>
            <ScrollView
              style={styles.mainSettingsScroll}
              contentContainerStyle={styles.mainSettingsScrollContent}
              showsVerticalScrollIndicator={false}
              keyboardShouldPersistTaps="handled"
              nestedScrollEnabled
              overScrollMode="never"
            >

            <Pressable style={styles.settingRow} onPress={() => setCountryPickerOpen(true)} hitSlop={{ top: 6, bottom: 6, left: 4, right: 4 }} accessibilityRole="button" accessibilityLabel={`${t("country")} · ${getStreamCountryName(country, language)}`}>
              <View>
                <Text style={styles.settingLabel}>{t("country")}</Text>
                <Text style={styles.settingValue}>{getStreamCountryName(country, language)}</Text>
              </View>
              <Ionicons name="chevron-forward" size={22} color="#8D8796" />
            </Pressable>

            <Pressable style={styles.settingRow} onPress={() => setNearby(!nearby)} hitSlop={{ top: 6, bottom: 6, left: 4, right: 4 }} accessibilityRole="switch" accessibilityState={{ checked: nearby }} accessibilityLabel={t("nearby")}>
              <View>
                <Text style={styles.settingLabel}>{t("nearby")}</Text>
                <Text style={styles.settingValue}>{nearby ? t("nearby") : t("all")}</Text>
              </View>
              <Ionicons name={nearby ? "checkmark-circle" : "ellipse-outline"} size={22} color="#F2C75B" />
            </Pressable>

            <View style={styles.categoryBlock}>
              <Text style={styles.settingLabel}>{t("type")}</Text>
              <ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.categoryPickerLine} nestedScrollEnabled overScrollMode="never">
                {visibleTypes.map((item) => (
                  <Chip key={item.id} active={type === item.id} icon={item.icon} label={item.label} onPress={() => setType(item.id)} t={t} />
                ))}
              </ScrollView>
            </View>

            <View style={styles.categoryBlock}>
              <Text style={styles.settingLabel}>{t("category")}</Text>
              <ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.categoryPickerLine} nestedScrollEnabled overScrollMode="never">
                {categories.map((item) => (
                  <Chip key={item.id} active={category === item.id} label={item.label} onPress={() => setCategory(item.id)} t={t} />
                ))}
              </ScrollView>
            </View>
            </ScrollView>
          </Pressable>
        </Pressable>
      </Modal>

      <CountryPickerModal
        visible={countryPickerOpen}
        selected={country}
        onSelect={setCountry}
        onClose={() => setCountryPickerOpen(false)}
        t={t}
        language={language}
      />
    </>
  );
}

function ControlsArea({
  country,
  setCountry,
  type,
  setType,
  category,
  setCategory,
  nearby,
  setNearby,
  query,
  setQuery,
  t,
  language,
}: {
  country: StreamCountryCode;
  setCountry: (country: StreamCountryCode) => void;
  type: FeedType;
  setType: (type: FeedType) => void;
  category: Category;
  setCategory: (category: Category) => void;
  nearby: boolean;
  setNearby: (nearby: boolean) => void;
  query: string;
  setQuery: (query: string) => void;
  t: (key: StreamTextKey) => string;
  language?: string | null;
}) {
  const [settingsOpen, setSettingsOpen] = useState(false);
  const hasActiveDiscovery = query.trim().length > 0 || country !== "all" || type !== "all" || category !== "all" || nearby;

  const resetDiscovery = () => {
    setQuery("");
    setCountry("all");
    setType("all");
    setCategory("all");
    setNearby(false);
  };

  return (
    <View style={styles.controlsArea}>
      <View style={styles.statusRow}>
        <View style={styles.streamScreenLabelPill}>
          <Ionicons name="radio-outline" size={13} color="#F2C75B" />
          <Text style={styles.streamScreenLabelText} numberOfLines={1}>{t("live")}</Text>
        </View>
        <View style={styles.sourceBadge}>
          <View style={styles.sourceDot} />
          <Text style={styles.sourceText} numberOfLines={1}>{t("realFeedOnly")}</Text>
        </View>
      </View>

      <View style={styles.searchRow}>
        <View style={styles.search}>
          <Ionicons name="search-outline" size={18} color="#908A99" />
          <TextInput
            value={query}
            onChangeText={setQuery}
            placeholder={t("search")}
            placeholderTextColor="#908A99"
            style={styles.searchInput}
            returnKeyType="search"
            autoCorrect={false}
            autoCapitalize="none"
            blurOnSubmit={false}
          />
          {hasActiveDiscovery ? (
            <Pressable style={styles.discoveryResetButton} onPress={resetDiscovery} hitSlop={8} accessibilityRole="button" accessibilityLabel={t("resetDiscovery")}>
              <Ionicons name="close-circle" size={19} color="#F2C75B" />
            </Pressable>
          ) : null}
        </View>
        <Pressable style={styles.mainSettingsButton} onPress={() => setSettingsOpen(true)} hitSlop={8} accessibilityRole="button" accessibilityLabel={t("mainSettings")}>
          <Ionicons name="options-outline" size={21} color="#F2C75B" />
        </Pressable>
      </View>

      <View style={styles.filterSummaryRow}>
        <ScrollView
          horizontal
          showsHorizontalScrollIndicator={false}
          contentContainerStyle={styles.discoveryRailContent}
          keyboardShouldPersistTaps="handled"
          nestedScrollEnabled
          overScrollMode="never"
        >
          {discoveryQuickFilters.map((item) => {
            const active = item.kind === "type" ? type === item.value : category === item.value;
            return (
              <Pressable
                key={item.id}
                style={[styles.discoveryChip, active ? styles.discoveryChipActive : null]}
                hitSlop={{ top: 6, bottom: 6, left: 3, right: 3 }}
                accessibilityRole="button"
                accessibilityState={{ selected: active }}
                accessibilityLabel={t(item.label)}
                onPress={() => {
                  if (item.kind === "type") {
                    setType(item.value);
                  } else {
                    setCategory(item.value);
                  }
                }}
              >
                <Ionicons name={item.icon} size={13} color={active ? "#09070D" : "#F2C75B"} />
                <Text style={[styles.discoveryChipText, active ? styles.discoveryChipTextActive : null]} numberOfLines={1}>{t(item.label)}</Text>
              </Pressable>
            );
          })}
          <View style={styles.discoveryProviderPill}>
            <View style={styles.sourceDot} />
            <Text style={styles.discoveryProviderText} numberOfLines={1}>{t("mainControlsReady")}</Text>
          </View>
        </ScrollView>
      </View>

      <MainSettingsModal
        visible={settingsOpen}
        country={country}
        setCountry={setCountry}
        type={type}
        setType={setType}
        category={category}
        setCategory={setCategory}
        nearby={nearby}
        setNearby={setNearby}
        onClose={() => setSettingsOpen(false)}
        t={t}
        language={language}
      />
    </View>
  );
}

