function FeedArea({
  streams,
  height,
  status,
  query,
  feedQuery,
  t,
  onOpen,
  onOpenTab,
}: {
  streams: LiveStreamCard[];
  height: number;
  status: FeedStatus;
  query: string;
  feedQuery: StreamFeedQueryContract;
  t: (key: StreamTextKey) => string;
  onOpen: (stream: LiveStreamCard) => void;
  onOpenTab: (tab: Tab) => void;
}) {
  const showSkeleton = status === "loading";
  const showError = status === "error";
  const showGrid = status === "ready" && streams.length > 0;
  const showEmpty = !showSkeleton && !showError && !showGrid;

  return (
    <View style={[styles.feedArea, { height }]}>
      <View style={styles.feedTopRule} />
      <View style={styles.feedClip}>
        {showSkeleton ? <FeedSkeleton /> : null}
        {showError ? <ErrorFeed t={t} /> : null}
        {showGrid ? (
          <ScrollView
            style={styles.feedGridScroll}
            contentContainerStyle={styles.grid}
            showsVerticalScrollIndicator={false}
            nestedScrollEnabled
            overScrollMode="never"
          >
            {streams.map((stream) => (
              <StreamTile key={stream.id} stream={stream} t={t} onOpen={onOpen} />
            ))}
          </ScrollView>
        ) : null}
        {showEmpty ? <EmptyFeed t={t} query={query} status={status} feedQuery={feedQuery} onOpenTab={onOpenTab} /> : null}
      </View>
    </View>
  );
}

type SafetyReason = "adultContent" | "harassment" | "fraud" | "violence" | "minorSafety" | "privacy" | "paymentAbuse";

const safetyReasons: { id: SafetyReason; label: StreamTextKey; icon: IconName }[] = [
  { id: "adultContent", label: "adultContent", icon: "eye-off-outline" },
  { id: "harassment", label: "harassment", icon: "chatbox-ellipses-outline" },
  { id: "fraud", label: "fraud", icon: "shield-outline" },
  { id: "violence", label: "violence", icon: "warning-outline" },
  { id: "minorSafety", label: "adultContent", icon: "finger-print-outline" },
  { id: "privacy", label: "policyLocked", icon: "lock-closed-outline" },
  { id: "paymentAbuse", label: "providerNotConfigured", icon: "card-outline" },
];

function StreamSafetyPanel({
  visible,
  selectedReason,
  setSelectedReason,
  submittedReason,
  localDrafts,
  onSubmitDraft,
  onClose,
  t,
}: {
  visible: boolean;
  selectedReason: SafetyReason | null;
  setSelectedReason: (reason: SafetyReason | null) => void;
  submittedReason: SafetyReason | null;
  localDrafts: number;
  onSubmitDraft: () => void;
  onClose: () => void;
  t: (key: StreamTextKey) => string;
}) {
  const { height: safetyWindowHeight } = useWindowDimensions();
  const safetyInsets = useSafeAreaInsets();
  const safetyCompactPhone = safetyWindowHeight < 720;
  const safetyVeryCompactPhone = safetyWindowHeight < 640;
  const safetyPanelMaxHeight = Math.max(360, safetyWindowHeight - safetyInsets.top - safetyInsets.bottom - 56);
  const safetyPanelBottom = Math.max(16, safetyInsets.bottom + 16);

  if (!visible) {
    return null;
  }

  const reportReasonSelected = selectedReason !== null;
  const reportDraftSubmitted = reportReasonSelected && submittedReason === selectedReason;
  const reportDraftReady = reportReasonSelected && !reportDraftSubmitted;
  const reportDraftMeta = reportDraftSubmitted ? `черновик уже создан · ${localDrafts}` : localDrafts > 0 ? `локальных черновиков: ${localDrafts}` : t("aiSignalOnly");
  const showUgcUiOnlyPreview = (title: string, body: string) => {
    Alert.alert(
      title,
      `${body}\n\nMobile UI-only: backend/admin moderation queue is not called in this patch. No fake moderation success.`,
    );
  };

  return (
    <View
      style={[styles.safetyPanel, { maxHeight: safetyPanelMaxHeight, bottom: safetyPanelBottom }, safetyCompactPhone ? styles.safetyPanelCompact : null]}
      onTouchStart={(event) => event.stopPropagation()}
    >
      <View style={styles.safetyTop}>
        <View style={styles.safetyTopText}>
          <Text style={[styles.safetyTitle, safetyCompactPhone ? styles.safetyTitleCompact : null]}>{t("safetyCenter")}</Text>
          <Text style={styles.safetyMeta}>{t("moderationLater")}</Text>
        </View>
        <Pressable style={styles.creatorModalClose} hitSlop={10} onPress={onClose} accessibilityRole="button" accessibilityLabel="Закрыть центр безопасности">
          <Ionicons name="close" size={22} color="#FFFFFF" />
        </Pressable>
      </View>

      <ScrollView
        style={styles.safetyScroll}
        contentContainerStyle={[styles.safetyScrollContent, safetyVeryCompactPhone ? styles.safetyScrollContentCompact : null]}
        showsVerticalScrollIndicator={false}
        nestedScrollEnabled
        overScrollMode="never"
        keyboardShouldPersistTaps="handled"
      >
        <View style={[styles.safetyNotice, reportReasonSelected || localDrafts > 0 ? styles.safetyNoticeActive : null]} accessibilityState={{ selected: reportReasonSelected || localDrafts > 0 }}>
          <View style={styles.sourceDot} />
          <Text style={[styles.safetyNoticeText, reportReasonSelected || localDrafts > 0 ? styles.safetyNoticeTextActive : null]}>{t("reportDraftOnly")} · {reportDraftMeta}</Text>
        </View>

        <View style={[styles.safetyQaCard, safetyCompactPhone ? styles.safetyQaCardCompact : null]} pointerEvents="none">
          <Text style={styles.safetyQaTitle}>UGC safety mobile UI-only · no fake moderation success</Text>
          <Text style={styles.safetyQaMeta}>provider_not_configured: moderation provider/admin queue is not connected in this mobile UI patch.</Text>
          <View style={styles.safetyQaRow}>
            <View style={styles.safetyQaPill}><Text style={styles.safetyQaPillText}>18+ gate</Text></View>
            <View style={styles.safetyQaPill}><Text style={styles.safetyQaPillText}>Report content</Text></View>
            <View style={styles.safetyQaPill}><Text style={styles.safetyQaPillText}>Report user</Text></View>
            <View style={styles.safetyQaPill}><Text style={styles.safetyQaPillText}>Block user</Text></View>
            <View style={styles.safetyQaPill}><Text style={styles.safetyQaPillText}>Comment hide</Text></View>
          </View>
        </View>

        <Text style={styles.safetySectionTitle}>{t("reportStream")}</Text>

        <View style={styles.safetyReasonsGrid}>
          {safetyReasons.map((reason) => {
            const active = selectedReason === reason.id;
            return (
              <Pressable
                key={reason.id}
                style={[styles.safetyReasonTile, safetyCompactPhone ? styles.safetyReasonTileCompact : null, active ? styles.safetyReasonTileActive : null]}
                hitSlop={8}
                onPress={() => setSelectedReason(active ? null : reason.id)}
                accessibilityRole="button"
                accessibilityState={{ selected: active }}
              >
                <Ionicons name={reason.icon} size={safetyCompactPhone ? 20 : 22} color={active ? "#09070D" : "#F2C75B"} />
                <Text style={[styles.safetyReasonText, safetyCompactPhone ? styles.safetyReasonTextCompact : null, active ? styles.safetyReasonTextActive : null]} numberOfLines={2}>
                  {t(reason.label)}
                </Text>
              </Pressable>
            );
          })}
        </View>

        <View style={styles.ugcActionGrid}>
          <Pressable
            style={styles.ugcActionTile}
            onPress={() => showUgcUiOnlyPreview("Report content", "Creates only a mobile UI evidence preview for reporting live/shorts content.")}
            accessibilityRole="button"
            accessibilityLabel="Report content"
          >
            <Ionicons name="flag-outline" size={18} color="#F2C75B" />
            <Text style={styles.ugcActionTitle}>Report content</Text>
          </Pressable>
          <Pressable
            style={styles.ugcActionTile}
            onPress={() => showUgcUiOnlyPreview("Report user", "Creates only a mobile UI evidence preview for reporting a streamer/user.")}
            accessibilityRole="button"
            accessibilityLabel="Report user"
          >
            <Ionicons name="person-remove-outline" size={18} color="#F2C75B" />
            <Text style={styles.ugcActionTitle}>Report user</Text>
          </Pressable>
          <Pressable
            style={styles.ugcActionTile}
            onPress={() => showUgcUiOnlyPreview("Block user", "Creates only a mobile UI evidence preview for block-user action.")}
            accessibilityRole="button"
            accessibilityLabel="Block user"
          >
            <Ionicons name="ban-outline" size={18} color="#F2C75B" />
            <Text style={styles.ugcActionTitle}>Block user</Text>
          </Pressable>
          <Pressable
            style={styles.ugcActionTile}
            onPress={() => showUgcUiOnlyPreview("Comment report / hide", "Creates only a mobile UI evidence preview for comment report/hide action.")}
            accessibilityRole="button"
            accessibilityLabel="Comment report or hide"
          >
            <Ionicons name="chatbox-ellipses-outline" size={18} color="#F2C75B" />
            <Text style={styles.ugcActionTitle}>Comment hide</Text>
          </Pressable>
        </View>

        <Text style={styles.ugcEvidenceCopy}>18+ gate evidence, minor-safety, abuse, privacy, and financial/payment abuse reasons are visible here. Final moderation persistence/admin queue must be connected later with separate approval.</Text>

        <Pressable
          style={[styles.submitReportButton, safetyCompactPhone ? styles.submitReportButtonCompact : null, reportDraftReady ? styles.submitReportButtonActive : styles.submitReportButtonDisabled]}
          onPress={onSubmitDraft}
          disabled={!reportDraftReady}
          accessibilityRole="button"
          accessibilityState={{ disabled: !reportDraftReady, selected: reportReasonSelected }}
        >
          <Text style={[styles.submitReportText, reportDraftReady ? null : styles.submitReportTextDisabled]}>{reportDraftSubmitted ? "Черновик уже подготовлен" : localDrafts > 0 ? `${t("submitReport")} · ${localDrafts}` : t("submitReport")}</Text>
        </Pressable>
      </ScrollView>
    </View>
  );
}

