function HomeScreen({
  t,
  topLimit,
  bottomLimit,
  screenHeight,
  screenWidth,
  language,
  onOpenTab,
}: {
  t: (key: StreamTextKey) => string;
  topLimit: number;
  bottomLimit: number;
  screenHeight: number;
  screenWidth: number;
  language?: string | null;
  onOpenTab: (tab: Tab) => void;
}) {
  const [country, setCountry] = useState<StreamCountryCode>("all");
  const [nearby, setNearby] = useState(false);
  const [type, setType] = useState<FeedType>("all");
  const [category, setCategory] = useState<Category>("all");
  const [query, setQuery] = useState("");
  const [selectedStream, setSelectedStream] = useState<LiveStreamCard | null>(null);
  const [scheduleAction, setScheduleAction] = useState<ScheduleAction | null>(null);

  const openSafeStreamRoute = (route: Tab | "shell") => {
    if (route === "shell") {
      return;
    }

    onOpenTab(route);
  };

  const feedQuery = useMemo(() => {
    return buildStreamFeedQueryContract({
      country,
      type,
      category,
      nearby,
      query,
    });
  }, [country, type, category, nearby, query]);

  const streams = useMemo(() => {
    return acceptsOnlyRealStreamCards(REAL_STREAMS, feedQuery).filter((item) => {
      const normalizedQuery = feedQuery.search.toLowerCase();
      if (feedQuery.country !== "all" && item.country !== feedQuery.country) return false;
      if (feedQuery.type !== "all" && item.type !== feedQuery.type) return false;
      if (feedQuery.category !== "all" && item.category !== feedQuery.category) return false;
      if (normalizedQuery && !`${item.title} ${item.host} ${item.type} ${item.category}`.toLowerCase().includes(normalizedQuery)) return false;
      return true;
    });
  }, [feedQuery]);

  const contentTop = topLimit + HEADER_HEIGHT;
  const visibleFeedHeight = screenHeight - contentTop - bottomLimit - CONTROL_HEIGHT - STATS_HEIGHT - UPCOMING_HEIGHT - 58;
  const feedHeight = Math.max(MIN_FEED_HEIGHT, Math.min(visibleFeedHeight, 520));

  return (
    <View style={styles.home}>
      <FixedBrandTitle t={t} top={topLimit} screenWidth={screenWidth} />

      <ScrollView
        style={styles.homeScroll}
        showsVerticalScrollIndicator={false}
        keyboardShouldPersistTaps="handled"
        nestedScrollEnabled
        overScrollMode="never"
        contentContainerStyle={[styles.homeContent, { paddingTop: contentTop, paddingBottom: bottomLimit + 64 }]}
        scrollIndicatorInsets={{ top: contentTop, bottom: bottomLimit + 64 }}
      >
        <ControlsArea
          country={country}
          setCountry={setCountry}
          type={type}
          setType={setType}
          category={category}
          setCategory={setCategory}
          nearby={nearby}
          setNearby={setNearby}
          query={query}
          setQuery={setQuery}
          t={t}
          language={language}
        />
        <StreamStatsBar t={t} />
        <UpcomingLiveStrip onAction={setScheduleAction} t={t} />
        <FeedArea
          streams={streams}
          height={feedHeight}
          status={FEED_STATUS}
          query={query}
          feedQuery={feedQuery}
          t={t}
          onOpen={(stream) => setSelectedStream(stream)}
          onOpenTab={openSafeStreamRoute}
        />
      </ScrollView>

      <StreamRoomViewer stream={selectedStream} onClose={() => setSelectedStream(null)} t={t} />
      <ScheduleActionModal action={scheduleAction} onClose={() => setScheduleAction(null)} t={t} />
    </View>
  );
}

function LiveModeSetupModal({
  mode,
  onOpenItem,
  onClose,
  t,
}: {
  mode: LiveMode | null;
  onOpenItem: (mode: LiveMode, item: LiveModeSetupItem) => void;
  onClose: () => void;
  t: (key: StreamTextKey) => string;
}) {
  const { height: liveModeWindowHeight, width: liveModeWindowWidth } = useWindowDimensions();
  const liveModeInsets = useSafeAreaInsets();
  const liveModeCompactPhone = liveModeWindowWidth < 380 || liveModeWindowHeight < 720;
  const liveModeSheetMaxHeight = Math.max(360, liveModeWindowHeight - liveModeInsets.top - liveModeInsets.bottom - 48);
  const liveModeSheetBottomPadding = Math.max(18, liveModeInsets.bottom + 16);

  if (!mode) {
    return null;
  }

  const modeMeta = liveModes.find((item) => item.id === mode);
  const items = getStream119aVisibleLiveModeSetupItems(mode);

  return (
    <Modal visible={Boolean(mode)} transparent animationType="fade" onRequestClose={onClose}>
      <Pressable style={styles.modalBackdrop} onPress={onClose}>
        <Pressable
          style={[styles.liveModeSheet, { maxHeight: liveModeSheetMaxHeight, paddingBottom: liveModeSheetBottomPadding }, liveModeCompactPhone ? styles.liveModeSheetCompact : null]}
          onPressIn={(event) => event.stopPropagation()}
          onPress={(event) => event.stopPropagation()}
        >
          <View style={styles.liveModeSheetTop}>
            <View style={styles.liveModeSheetIcon}>
              <Ionicons name={modeMeta?.icon ?? "radio-outline"} size={26} color="#F2C75B" />
            </View>
            <View style={styles.liveModeSheetTitleWrap}>
              <Text style={styles.liveModeSheetTitle} numberOfLines={1}>{mode === "businessLive" ? t("businessLiveModeUi") : t(liveModeSetupTitles[mode])}</Text>
              <Text style={styles.liveModeSheetMeta} numberOfLines={2}>{mode === "businessLive" ? `${t("shoppingOnlyBusiness")} · ${t("commerceLockedNoProvider")}` : `${t(liveModeSetupSummaries[mode])} · ${t("modeLocked")}`}</Text>
            </View>
            <Pressable style={styles.creatorModalClose} hitSlop={10} onPress={onClose} accessibilityRole="button" accessibilityLabel="Закрыть окно">
              <Ionicons name="close" size={22} color="#FFFFFF" />
            </Pressable>
          </View>

          <View style={styles.liveModeSafety}>
            <View style={styles.sourceDot} />
            <Text style={styles.liveModeSafetyText} numberOfLines={2}>
              {mode === "businessLive" ? `${t("shoppingOnlyBusiness")} · ${t("noBuyButtonBeforeProvider")} · ${t("noFakeBusinessPayment")}` : `${t("ordinaryModesNoCommerce")} · ${t("noCartInOrdinaryLive")} · ${t("noFakeLiveStart")}`}
            </Text>
          </View>

          <ScrollView
            style={[styles.liveModeGridScroll, liveModeCompactPhone ? styles.liveModeGridScrollCompact : null]}
            contentContainerStyle={[styles.liveModeGrid, { paddingBottom: Math.max(6, liveModeSheetBottomPadding - 12) }, liveModeCompactPhone ? styles.liveModeGridCompact : null]}
            showsVerticalScrollIndicator={false}
            nestedScrollEnabled
            overScrollMode="never"
            keyboardShouldPersistTaps="handled"
          >
            {items.map((item) => (
              <Pressable
                key={`${item.title}-${item.status}`}
                style={[styles.liveModeConfigTile, liveModeCompactPhone ? styles.liveModeConfigTileCompact : null]}
                hitSlop={6}
                onPress={() => onOpenItem(mode, item)}
                accessibilityRole="button"
                accessibilityLabel={`${t(item.title)} · ${t(item.status)}`}
              >
                <View style={styles.liveModeConfigIcon}>
                  <Ionicons name={item.icon} size={22} color="#F2C75B" />
                </View>
                <Text style={styles.liveModeConfigTitle} numberOfLines={1}>{t(item.title)}</Text>
                <Text style={styles.liveModeConfigStatus} numberOfLines={1}>{t(item.status)}</Text>
              </Pressable>
            ))}
          </ScrollView>

          <Pressable
            style={[styles.configureLockedButton, liveModeCompactPhone ? styles.configureLockedButtonCompact : null]}
            disabled={true}
            accessibilityRole="button"
            accessibilityState={{ disabled: true }}
            accessibilityLabel={t("configureLocked")}
          >
            <Text style={styles.configureLockedText} numberOfLines={1}>{t("configureLocked")}</Text>
          </Pressable>
        </Pressable>
      </Pressable>
    </Modal>
  );
}

