function PlaceholderStage({
  title,
  icon,
  t,
}: {
  title: StreamTextKey;
  icon: IconName;
  t: (key: StreamTextKey) => string;
}) {
  return (
    <View style={styles.stage}>
      <LinearGradient colors={["#07060B", "#000000"]} style={styles.stageGradient}>
        <View style={styles.stageTop}>
          <Text style={styles.stageTitle}>{t(title)}</Text>
          <View style={styles.sourceBadge}>
            <View style={styles.sourceDot} />
            <Text style={styles.sourceText}>{t("providerLater")}</Text>
          </View>
        </View>
        <View style={styles.stageCenter}>
          <View style={styles.stageLens}>
            <Ionicons name={icon} size={58} color="#F2C75B" />
          </View>
        </View>
      </LinearGradient>
    </View>
  );
}

function ShortsSkeleton() {
  return (
    <View style={styles.shortsSkeleton}>
      <View style={styles.shortsSkeletonCenter} />
      <View style={styles.shortsSkeletonBottom} />
    </View>
  );
}

function ShortsEmpty({ t }: { t: (key: StreamTextKey) => string }) {
  return (
    <View style={styles.shortsEmpty}>
      <View style={styles.emptyRing}>
        <Ionicons name="play-circle-outline" size={50} color="#F2C75B" />
      </View>
      <Text style={styles.emptyTitle}>{t("realShorts")}</Text>
      <Text style={styles.emptyMeta}>{t("videoProviderLater")}</Text>
    </View>
  );
}

function ShortsViewer({
  shorts,
  status,
  t,
  editActive = false,
  editLabel,
  previewColors,
  draftTitle,
  draftSoundLabel,
  onEditDraft,
  onClearDraft,
}: {
  shorts: ShortVideoCard[];
  status: FeedStatus;
  t: (key: StreamTextKey) => string;
  editActive?: boolean;
  editLabel?: string;
  previewColors?: [string, string];
  draftTitle?: string;
  draftSoundLabel?: string;
  onEditDraft?: () => void;
  onClearDraft?: () => void;
}) {
  const current = shorts[0];
  const surfaceColors = previewColors ?? ["#16111F", "#050509"];

  if (status === "loading") {
    return <ShortsSkeleton />;
  }

  if (status === "error") {
    return <ErrorFeed t={t} />;
  }

  if (!current && !editActive) {
    return <ShortsEmpty t={t} />;
  }

  if (!current) {
    return (
      <View style={styles.shortVideoFrame}>
        <LinearGradient colors={surfaceColors} style={styles.shortVideoSurface}>
          <Ionicons name="cut-outline" size={58} color="#F2C75B" />
        </LinearGradient>

        {editLabel ? (
          <View style={styles.shortPreviewEditPill}>
            <Ionicons name="options-outline" size={13} color="#F2C75B" />
            <Text style={styles.shortPreviewEditText} numberOfLines={1}>{editLabel}</Text>
          </View>
        ) : null}

        <View style={styles.shortInfoLayer}>
          <View style={styles.shortCreatorAvatar} />
          <View style={styles.shortInfoText}>
            <Text style={styles.shortCreatorName} numberOfLines={1}>Вы</Text>
            <Text style={styles.shortTitle} numberOfLines={2}>{draftTitle ?? DEFAULT_SHORT_DRAFT_TITLE}</Text>
            <Text style={styles.shortSound} numberOfLines={1}>{draftSoundLabel ?? "Монтаж только на телефоне"}</Text>
          </View>
        </View>

        <View style={styles.shortLocalDraftActions}>
          <Pressable style={styles.shortLocalDraftPrimaryButton} onPress={onEditDraft} accessibilityLabel="Редактировать локальный черновик Shorts">
            <Ionicons name="create-outline" size={16} color="#09070D" />
            <Text style={styles.shortLocalDraftPrimaryText}>Редактировать</Text>
          </Pressable>
          <Pressable style={styles.shortLocalDraftGhostButton} onPress={onClearDraft} accessibilityLabel="Очистить локальный черновик Shorts">
            <Ionicons name="trash-outline" size={15} color="#FFFFFF" />
            <Text style={styles.shortLocalDraftGhostText}>Очистить</Text>
          </Pressable>
        </View>
      </View>
    );
  }

  return (
    <View style={styles.shortVideoFrame}>
      <LinearGradient colors={surfaceColors} style={styles.shortVideoSurface}>
        <Ionicons name="play-circle-outline" size={64} color="#F2C75B" />
      </LinearGradient>

      {editActive && editLabel ? (
        <View style={styles.shortPreviewEditPill}>
          <Ionicons name="options-outline" size={13} color="#F2C75B" />
          <Text style={styles.shortPreviewEditText} numberOfLines={1}>{editLabel}</Text>
        </View>
      ) : null}

      <View style={styles.shortInfoLayer}>
        <View style={styles.shortCreatorAvatar} />
        <View style={styles.shortInfoText}>
          <Text style={styles.shortCreatorName} numberOfLines={1}>{current.creator}</Text>
          <Text style={styles.shortTitle} numberOfLines={2}>{current.title}</Text>
          <Text style={styles.shortSound} numberOfLines={1}>{t("sound")} · {t(current.category)}</Text>
        </View>
      </View>
    </View>
  );
}

type LocalShortComment = {
  readonly id: string;
  readonly author: string;
  readonly text: string;
  readonly status: string;
  readonly liked: boolean;
};

type ShortEditorEffectId = "clean" | "warm" | "contrast" | "cinema";
type ShortEditorAudioModeId = "original" | "voice" | "soft" | "fast";

type ShortEditorOption<T extends string> = {
  readonly id: T;
  readonly title: string;
  readonly meta: string;
  readonly icon: IconName;
};

const SHORT_EDITOR_EFFECTS: ShortEditorOption<ShortEditorEffectId>[] = [
  { id: "clean", title: "Clean", meta: "без фильтра", icon: "color-filter-outline" },
  { id: "warm", title: "Warm", meta: "мягкий тон", icon: "sunny-outline" },
  { id: "contrast", title: "Contrast", meta: "чёткая картинка", icon: "contrast-outline" },
  { id: "cinema", title: "Cinema", meta: "кино-тон", icon: "film-outline" },
];

const SHORT_EDITOR_AUDIO_MODES: ShortEditorOption<ShortEditorAudioModeId>[] = [
  { id: "original", title: "Original", meta: "звук видео", icon: "mic-outline" },
  { id: "voice", title: "Voice", meta: "голос впереди", icon: "radio-outline" },
  { id: "soft", title: "Soft beat", meta: "тихий фон", icon: "musical-notes-outline" },
  { id: "fast", title: "Fast cut", meta: "быстрый ритм", icon: "flash-outline" },
];

const DEFAULT_SHORT_DRAFT_TITLE = "Локальный черновик Shorts";

function ShortsScreen({ t }: { t: (key: StreamTextKey) => string }) {
  const [section, setSection] = useState<"forYou" | "following">("forYou");
  const [liked, setLiked] = useState(false);
  const [saved, setSaved] = useState(false);
  const [commentsOpen, setCommentsOpen] = useState(false);
  const [editorOpen, setEditorOpen] = useState(false);
  const [commentDraft, setCommentDraft] = useState("");
  const [comments, setComments] = useState<LocalShortComment[]>([]);
  const [selectedEffect, setSelectedEffect] = useState<ShortEditorEffectId>("clean");
  const [selectedAudioMode, setSelectedAudioMode] = useState<ShortEditorAudioModeId>("original");
  const [selectedMp3Name, setSelectedMp3Name] = useState<string | null>(null);
  const [localDraftTitle, setLocalDraftTitle] = useState(DEFAULT_SHORT_DRAFT_TITLE);
  const [shortFeedback, setShortFeedback] = useState<string | null>(null);

  const selectedEffectOption = SHORT_EDITOR_EFFECTS.find((effect) => effect.id === selectedEffect) ?? SHORT_EDITOR_EFFECTS[0];
  const selectedAudioModeOption = SHORT_EDITOR_AUDIO_MODES.find((mode) => mode.id === selectedAudioMode) ?? SHORT_EDITOR_AUDIO_MODES[0];
  const cleanDraftTitle = localDraftTitle.trim() || DEFAULT_SHORT_DRAFT_TITLE;
  const hasCustomDraftTitle = cleanDraftTitle !== DEFAULT_SHORT_DRAFT_TITLE;
  const hasEditorSelection = hasCustomDraftTitle || selectedEffect !== "clean" || selectedAudioMode !== "original" || Boolean(selectedMp3Name);
  const editorSelectionLabel = `${cleanDraftTitle} · ${selectedEffectOption.title} · ${selectedAudioModeOption.title}${selectedMp3Name ? ` · ${selectedMp3Name}` : ""}`;
  const draftSoundLabel = `${selectedAudioModeOption.title}${selectedMp3Name ? ` · ${selectedMp3Name}` : ""}`;
  const previewColors: [string, string] = selectedEffect === "warm"
    ? ["#3A2417", "#070509"]
    : selectedEffect === "contrast"
      ? ["#0B0A12", "#000000"]
      : selectedEffect === "cinema"
        ? ["#151525", "#030306"]
        : ["#16111F", "#050509"];

  const resetLocalEditorState = () => {
    setSelectedEffect("clean");
    setSelectedAudioMode("original");
    setSelectedMp3Name(null);
    setLocalDraftTitle(DEFAULT_SHORT_DRAFT_TITLE);
    showShortFeedback("Черновик очищен");
  };

  const finishLocalEditorState = () => {
    setEditorOpen(false);
    showShortFeedback(hasEditorSelection ? "Монтаж сохранён локально" : "Редактор закрыт");
  };

  const submitLocalComment = () => {
    const cleaned = commentDraft.trim();
    if (!cleaned) {
      return;
    }

    setComments((current) => [
      {
        id: `local-comment-${Date.now()}`,
        author: "Вы",
        text: cleaned,
        status: "Локально",
        liked: false,
      },
      ...current,
    ]);
    setCommentDraft("");
  };

  const toggleLocalCommentLike = (commentId: string) => {
    setComments((current) => current.map((comment) => (
      comment.id === commentId ? { ...comment, liked: !comment.liked } : comment
    )));
  };

  const removeLocalComment = (commentId: string) => {
    setComments((current) => current.filter((comment) => comment.id !== commentId));
  };

  const commentCountLabel = comments.length === 0
    ? "Пока пусто"
    : comments.length === 1
      ? "1 комментарий"
      : `${comments.length} комментария`;
  const canSubmitComment = commentDraft.trim().length > 0;

  const showShortFeedback = (message: string) => {
    setShortFeedback(message);
  };

  const toggleLocalSave = () => {
    const nextSavedState = !saved;
    setSaved(nextSavedState);
    showShortFeedback(nextSavedState ? "Сохранено локально" : "Убрано из сохранённых");
  };

  const shareShort = async () => {
    try {
      const result = await Share.share({ message: "Sabi Stream Shorts" });
      showShortFeedback(result.action === Share.sharedAction ? "Открыто системное меню" : "Поделиться отменено");
    } catch {
      showShortFeedback("Не удалось открыть поделиться");
    }
  };

  const pickLocalMp3 = async () => {
    try {
      const result = await DocumentPicker.getDocumentAsync({
        type: "audio/*",
        copyToCacheDirectory: true,
        multiple: false,
      });

      if (result.canceled) {
        return;
      }

      const asset = result.assets?.[0];
      const fileName = asset?.name ?? "audio file";
      setSelectedMp3Name(fileName);
      showShortFeedback(`MP3 выбран: ${fileName}`);
    } catch {
      setSelectedMp3Name("Ошибка выбора");
      showShortFeedback("MP3 не выбран");
    }
  };

  const clearLocalMp3Track = () => {
    setSelectedMp3Name(null);
    showShortFeedback("MP3 убран из локального монтажа");
  };

  return (
    <View style={styles.stage}>
      <LinearGradient colors={["#050509", "#000000"]} style={styles.stageGradient}>
        <View style={styles.shortTop}>
          <Chip active={section === "forYou"} label="forYou" onPress={() => setSection("forYou")} t={t} />
          <Chip active={section === "following"} label="following" onPress={() => setSection("following")} t={t} />
          <View style={styles.sourceBadge}>
            <View style={styles.sourceDot} />
            <Text style={styles.sourceText} numberOfLines={1}>{t("realDataOnly")}</Text>
          </View>
        </View>

        <ShortsViewer
          shorts={REAL_SHORTS}
          status={SHORTS_STATUS}
          t={t}
          editActive={hasEditorSelection}
          editLabel={editorSelectionLabel}
          previewColors={previewColors}
          draftTitle={cleanDraftTitle}
          draftSoundLabel={draftSoundLabel}
          onEditDraft={() => setEditorOpen(true)}
          onClearDraft={resetLocalEditorState}
        />

        <View style={styles.shortActions}>
          <Pressable
            style={[styles.shortActionButton, liked ? styles.shortActionButtonActive : null]}
            onPress={() => {
              const nextLikedState = !liked;
              setLiked(nextLikedState);
              showShortFeedback(nextLikedState ? "Лайк поставлен локально" : "Лайк убран");
            }}
            accessibilityLabel="Лайк"
          >
            <Ionicons name={liked ? "heart" : "heart-outline"} size={24} color={liked ? "#0B0910" : "#FFFFFF"} />
            <Text style={[styles.shortActionText, liked ? styles.shortActionTextActive : null]}>Лайк</Text>
          </Pressable>

          <Pressable style={styles.shortActionButton} onPress={() => setCommentsOpen(true)} accessibilityLabel="Комментарии">
            {comments.length > 0 ? <Text style={styles.shortActionCounter}>{comments.length}</Text> : null}
            <Ionicons name="chatbubble-ellipses-outline" size={24} color="#FFFFFF" />
            <Text style={styles.shortActionText}>Коммент</Text>
          </Pressable>

          <Pressable
            style={[styles.shortActionButton, saved ? styles.shortActionButtonActive : null]}
            onPress={toggleLocalSave}
            accessibilityLabel="Сохранить"
          >
            <Ionicons name={saved ? "bookmark" : "bookmark-outline"} size={23} color={saved ? "#0B0910" : "#FFFFFF"} />
            <Text style={[styles.shortActionText, saved ? styles.shortActionTextActive : null]}>Сохранить</Text>
          </Pressable>

          <Pressable style={styles.shortActionButton} onPress={shareShort} accessibilityLabel="Поделиться">
            <Ionicons name="share-social-outline" size={23} color="#FFFFFF" />
            <Text style={styles.shortActionText}>Поделиться</Text>
          </Pressable>
        </View>

        {shortFeedback ? (
          <View style={styles.shortFeedbackPill}>
            <Ionicons name="information-circle-outline" size={15} color="#F2C75B" />
            <Text style={styles.shortFeedbackText} numberOfLines={1}>{shortFeedback}</Text>
          </View>
        ) : null}

        <View style={styles.shortDock}>
          <Pressable style={styles.shortDockButton} onPress={() => setEditorOpen(true)} accessibilityLabel="Открыть редактор Shorts">
            <Text style={styles.shortDockText}>Редактор</Text>
          </Pressable>
          <Pressable style={styles.shortDockButton} onPress={() => setCommentsOpen(true)} accessibilityLabel="Открыть комментарии">
            <Text style={styles.shortDockText}>Комментарии</Text>
          </Pressable>
          <Pressable style={styles.shortDockButton} onPress={shareShort} accessibilityLabel="Поделиться видео">
            <Text style={styles.shortDockText}>Поделиться</Text>
          </Pressable>
        </View>

        <StreamShortVideoDraftPanel />

        <Modal visible={commentsOpen} animationType="slide" transparent onRequestClose={() => setCommentsOpen(false)}>
          <KeyboardAvoidingView
            style={styles.shortModalKeyboardAvoider}
            behavior={Platform.OS === "ios" ? "padding" : undefined}
            keyboardVerticalOffset={0}
          >
            <Pressable style={styles.modalBackdrop} onPress={() => setCommentsOpen(false)}>
              <Pressable
                style={styles.shortCommentsSheet}
                onPressIn={(event) => event.stopPropagation()}
                onPress={(event) => event.stopPropagation()}
                onTouchStart={(event) => event.stopPropagation()}
              >
                <View style={styles.shortCommentsTop}>
                  <View>
                    <Text style={styles.shortCommentsTitle}>Комментарии</Text>
                    <Text style={styles.shortCommentsMeta}>{commentCountLabel}</Text>
                  </View>
                  <Pressable style={styles.preLiveSideStatusClose} hitSlop={8} onPress={() => setCommentsOpen(false)} accessibilityRole="button" accessibilityLabel="Закрыть комментарии">
                    <Ionicons name="close-outline" size={18} color="#FFFFFF" />
                  </Pressable>
                </View>

                <ScrollView
                  style={styles.shortCommentsList}
                  contentContainerStyle={styles.shortCommentsListContent}
                  keyboardShouldPersistTaps="handled"
                  nestedScrollEnabled
                >
                  {comments.length === 0 ? (
                    <View style={styles.shortCommentsEmpty}>
                      <Ionicons name="chatbubble-ellipses-outline" size={28} color="#F2C75B" />
                      <Text style={styles.shortCommentsEmptyText}>Напишите первый комментарий</Text>
                    </View>
                  ) : comments.map((comment) => (
                    <View key={comment.id} style={styles.shortCommentRow}>
                      <View style={styles.shortCommentAvatar} />
                      <View style={styles.shortCommentBubble}>
                        <View style={styles.shortCommentTopLine}>
                          <Text style={styles.shortCommentAuthor}>{comment.author}</Text>
                          <Text style={styles.shortCommentReport}>⋯</Text>
                        </View>
                        <Text style={styles.shortCommentText}>{comment.text}</Text>
                        <View style={styles.shortCommentActions}>
                          <Pressable
                            style={[styles.shortCommentActionButton, comment.liked ? styles.shortCommentActionButtonActive : null]}
                            onPress={() => toggleLocalCommentLike(comment.id)}
                            accessibilityLabel="Лайк комментария"
                          >
                            <Ionicons name={comment.liked ? "heart" : "heart-outline"} size={14} color={comment.liked ? "#09070D" : "#F2C75B"} />
                            <Text style={[styles.shortCommentActionText, comment.liked ? styles.shortCommentActionTextActive : null]}>Нравится</Text>
                          </Pressable>
                          <Pressable
                            style={[styles.shortCommentActionButton, styles.shortCommentActionButtonDanger]}
                            onPress={() => removeLocalComment(comment.id)}
                            accessibilityLabel="Удалить локальный комментарий"
                          >
                            <Ionicons name="trash-outline" size={14} color="#FFB8B8" />
                            <Text style={styles.shortCommentActionTextDanger}>Удалить</Text>
                          </Pressable>
                        </View>
                        <Text style={styles.shortCommentStatus}>{comment.status}</Text>
                      </View>
                    </View>
                  ))}
                </ScrollView>

                <View style={styles.shortCommentComposer}>
                  <TextInput
                    value={commentDraft}
                    onChangeText={setCommentDraft}
                    placeholder="Написать комментарий"
                    placeholderTextColor="#8D8796"
                    style={styles.shortCommentInput}
                    returnKeyType="send"
                    onSubmitEditing={submitLocalComment}
                  />
                  <Pressable style={[styles.shortCommentSendButton, !canSubmitComment ? styles.shortCommentSendButtonDisabled : null]} onPress={submitLocalComment} accessibilityLabel="Отправить комментарий">
                    <Ionicons name="send-outline" size={18} color="#0B0910" />
                  </Pressable>
                </View>
              </Pressable>
            </Pressable>
          </KeyboardAvoidingView>
        </Modal>

        <Modal visible={editorOpen} animationType="slide" transparent onRequestClose={() => setEditorOpen(false)}>
          <Pressable style={styles.modalBackdrop} onPress={() => setEditorOpen(false)}>
            <Pressable
              style={styles.shortEditorSheet}
              onPressIn={(event) => event.stopPropagation()}
              onPress={(event) => event.stopPropagation()}
              onTouchStart={(event) => event.stopPropagation()}
            >
              <ScrollView
                style={styles.shortEditorScroll}
                contentContainerStyle={styles.shortEditorSheetContent}
                keyboardShouldPersistTaps="handled"
                nestedScrollEnabled
                showsVerticalScrollIndicator={false}
              >
                <View style={styles.shortEditorTop}>
                <View style={styles.shortEditorIcon}>
                  <Ionicons name="cut-outline" size={22} color="#F2C75B" />
                </View>
                <View style={styles.shortEditorTitleWrap}>
                  <Text style={styles.shortEditorTitle}>Редактор Shorts</Text>
                  <Text style={styles.shortEditorMeta}>Эффект, звук и MP3 выбираются локально</Text>
                </View>
                <Pressable style={styles.preLiveSideStatusClose} hitSlop={8} onPress={() => setEditorOpen(false)} accessibilityRole="button" accessibilityLabel="Закрыть редактор Shorts">
                  <Ionicons name="close-outline" size={18} color="#FFFFFF" />
                </Pressable>
              </View>

              <View style={styles.shortEditorSummary}>
                <Ionicons name="shield-checkmark-outline" size={17} color="#F2C75B" />
                <Text style={styles.shortEditorSummaryText} numberOfLines={2}>
                  Локальный черновик: без загрузки и без публикации.
                </Text>
              </View>

              <View style={styles.shortEditorTitleField}>
                <Text style={styles.shortEditorTitleFieldLabel}>Название черновика</Text>
                <TextInput
                  value={localDraftTitle}
                  onChangeText={setLocalDraftTitle}
                  placeholder="Название Shorts"
                  placeholderTextColor="#8D8796"
                  maxLength={64}
                  style={styles.shortEditorTitleInput}
                  returnKeyType="done"
                />
              </View>

              <View style={styles.shortEditorCurrentCard}>
                <View style={styles.shortEditorCurrentTop}>
                  <View style={styles.shortEditorCurrentTitleWrap}>
                    <Text style={styles.shortEditorCurrentTitle}>Текущий монтаж</Text>
                    <Text style={styles.shortEditorCurrentMeta} numberOfLines={1}>{editorSelectionLabel}</Text>
                  </View>
                  {hasEditorSelection ? (
                    <Pressable style={styles.shortEditorResetButton} onPress={resetLocalEditorState} accessibilityLabel="Сбросить редактор Shorts">
                      <Text style={styles.shortEditorResetText}>Сбросить</Text>
                    </Pressable>
                  ) : null}
                </View>

                <View style={styles.shortEditorCurrentChips}>
                  <View style={styles.shortEditorCurrentChip}>
                    <Ionicons name={selectedEffectOption.icon} size={14} color="#F2C75B" />
                    <Text style={styles.shortEditorCurrentChipText} numberOfLines={1}>{selectedEffectOption.title}</Text>
                  </View>
                  <View style={styles.shortEditorCurrentChip}>
                    <Ionicons name={selectedAudioModeOption.icon} size={14} color="#F2C75B" />
                    <Text style={styles.shortEditorCurrentChipText} numberOfLines={1}>{selectedAudioModeOption.title}</Text>
                  </View>
                  <View style={styles.shortEditorCurrentChip}>
                    <Ionicons name="musical-note-outline" size={14} color="#F2C75B" />
                    <Text style={styles.shortEditorCurrentChipText} numberOfLines={1}>{selectedMp3Name ?? "MP3 нет"}</Text>
                  </View>
                </View>
              </View>

              <View style={styles.shortEditorSection}>
                <Text style={styles.shortEditorSectionTitle}>Эффекты</Text>
                <View style={styles.shortEditorGrid}>
                  {SHORT_EDITOR_EFFECTS.map((effect) => {
                    const active = effect.id === selectedEffect;
                    return (
                      <Pressable
                        key={effect.id}
                        style={[styles.shortEditorOption, active ? styles.shortEditorOptionActive : null]}
                        onPress={() => {
                          setSelectedEffect(effect.id);
                          showShortFeedback(`Эффект: ${effect.title}`);
                        }}
                        accessibilityLabel={`Выбрать эффект ${effect.title}`}
                      >
                        <Ionicons name={effect.icon} size={18} color={active ? "#09070D" : "#F2C75B"} />
                        <Text style={[styles.shortEditorOptionTitle, active ? styles.shortEditorOptionTitleActive : null]}>{effect.title}</Text>
                        <Text style={[styles.shortEditorOptionMeta, active ? styles.shortEditorOptionMetaActive : null]}>{effect.meta}</Text>
                      </Pressable>
                    );
                  })}
                </View>
              </View>

              <View style={styles.shortEditorSection}>
                <Text style={styles.shortEditorSectionTitle}>Звук</Text>
                <View style={styles.shortEditorGrid}>
                  {SHORT_EDITOR_AUDIO_MODES.map((mode) => {
                    const active = mode.id === selectedAudioMode;
                    return (
                      <Pressable
                        key={mode.id}
                        style={[styles.shortEditorOption, active ? styles.shortEditorOptionActive : null]}
                        onPress={() => {
                          setSelectedAudioMode(mode.id);
                          showShortFeedback(`Звук: ${mode.title}`);
                        }}
                        accessibilityLabel={`Выбрать звук ${mode.title}`}
                      >
                        <Ionicons name={mode.icon} size={18} color={active ? "#09070D" : "#F2C75B"} />
                        <Text style={[styles.shortEditorOptionTitle, active ? styles.shortEditorOptionTitleActive : null]}>{mode.title}</Text>
                        <Text style={[styles.shortEditorOptionMeta, active ? styles.shortEditorOptionMetaActive : null]}>{mode.meta}</Text>
                      </Pressable>
                    );
                  })}
                </View>
              </View>

              <Pressable style={styles.shortEditorMp3Button} onPress={pickLocalMp3} accessibilityLabel="Выбрать MP3 файл">
                <Ionicons name="folder-open-outline" size={19} color="#09070D" />
                <View style={styles.shortEditorMp3TextWrap}>
                  <Text style={styles.shortEditorMp3Title}>{selectedMp3Name ? "MP3 выбран" : "Выбрать MP3"}</Text>
                  <Text style={styles.shortEditorMp3Meta} numberOfLines={1}>{selectedMp3Name ?? "локально с телефона"}</Text>
                </View>
              </Pressable>

              {selectedMp3Name ? (
                <Pressable style={styles.shortEditorRemoveMp3Button} onPress={clearLocalMp3Track} accessibilityLabel="Убрать MP3 из локального монтажа">
                  <Ionicons name="close-circle-outline" size={18} color="#FFB8B8" />
                  <Text style={styles.shortEditorRemoveMp3Text} numberOfLines={1}>Убрать MP3</Text>
                </Pressable>
              ) : null}

              <Pressable style={styles.shortEditorDoneButton} onPress={finishLocalEditorState} accessibilityLabel="Готово редактор Shorts">
                <Text style={styles.shortEditorDoneText}>Готово</Text>
                <Ionicons name="checkmark-circle-outline" size={19} color="#09070D" />
              </Pressable>
              </ScrollView>
            </Pressable>
          </Pressable>
        </Modal>
      </LinearGradient>
    </View>
  );
}

type BusinessTileAction = "merchant" | "catalog" | "supplier" | "chat" | "qr" | "wallet";

type BusinessTile = {
  icon: IconName;
  title: StreamTextKey;
  status: StreamTextKey;
  action: BusinessTileAction;
};

type BusinessPreviewCard = {
  icon: IconName;
  title: StreamTextKey;
  status: StreamTextKey;
  gate: StreamTextKey;
};

const businessTiles: BusinessTile[] = [
  { icon: "storefront-outline", title: "merchantLive", status: "merchantProviderLater", action: "merchant" },
  { icon: "cube-outline", title: "productShowcase", status: "catalogLater", action: "catalog" },
  { icon: "people-outline", title: "supplierRoom", status: "reviewRequired", action: "supplier" },
  { icon: "chatbubbles-outline", title: "businessChat", status: "messengerLater", action: "chat" },
  { icon: "qr-code-outline", title: "qrPayLocked", status: "paymentsLocked", action: "qr" },
  { icon: "wallet-outline", title: "walletProviderLater", status: "safeLocked", action: "wallet" },
];

const businessSetupSteps: { icon: IconName; title: StreamTextKey; status: StreamTextKey }[] = [
  { icon: "shield-checkmark-outline", title: "businessAdminApproval", status: "adminApprovalRequiredShort" },
  { icon: "cube-outline", title: "businessProductShelf", status: "productApprovalRequired" },
  { icon: "pricetag-outline", title: "businessLiveOffers", status: "offersLocked" },
  { icon: "receipt-outline", title: "businessOrderRules", status: "ordersLocked" },
  { icon: "wallet-outline", title: "businessWalletReadiness", status: "walletProviderLater" },
];

const businessProductPreviewCards: BusinessPreviewCard[] = [
  { icon: "storefront-outline", title: "merchantProfile", status: "merchantProviderLater", gate: "adminApprovalRequiredShort" },
  { icon: "cube-outline", title: "productShelf", status: "productProviderLater", gate: "productApprovalRequired" },
  { icon: "pricetag-outline", title: "businessLiveOffers", status: "offersLocked", gate: "reviewRequired" },
  { icon: "receipt-outline", title: "cartPreview", status: "cartProviderLater", gate: "ordersLocked" },
];

const businessCheckoutLockedSteps: BusinessPreviewCard[] = [
  { icon: "wallet-outline", title: "walletCheckout", status: "paymentProviderLater", gate: "walletProviderLater" },
  { icon: "qr-code-outline", title: "qrPay", status: "qrPayLocked", gate: "paymentsLocked" },
  { icon: "receipt-outline", title: "orders", status: "orderPreviewLocked", gate: "noFakeOrder" },
];

const businessVisualQaSteps: BusinessPreviewCard[] = [
  { icon: "shield-checkmark-outline", title: "adminApprovalRequiredShort", status: "reviewRequired", gate: "safeLocked" },
  { icon: "cube-outline", title: "businessProductShelf", status: "productApprovalRequired", gate: "draftOnly" },
  { icon: "wallet-outline", title: "walletCheckout", status: "walletProviderLater", gate: "noFakeCheckout" },
  { icon: "receipt-outline", title: "orders", status: "ordersLocked", gate: "noFakeOrder" },
];

function BusinessStreamScreen({ t }: { t: (key: StreamTextKey) => string }) {
  const insets = useSafeAreaInsets();
  const { height } = useWindowDimensions();
  const compactPhone = height < 740;
  const [selectedBusinessAction, setSelectedBusinessAction] = useState<BusinessTileAction>("merchant");
  const selectedBusinessTile = businessTiles.find((tile) => tile.action === selectedBusinessAction) ?? businessTiles[0];

  return (
    <View style={[styles.businessScreen, { paddingBottom: Math.max(insets.bottom + 28, 36) }]} onTouchStart={(event) => event.stopPropagation()}>
      <LinearGradient colors={["#191421", "#0C0A11"]} style={[styles.businessHero, compactPhone ? styles.businessHeroCompact : null]}>
        <View style={styles.businessHeroLeft}>
          <View style={styles.businessHeroBadgeRow}>
            <View style={styles.businessHeroBadge}>
              <Ionicons name="shield-checkmark-outline" size={13} color="#F2C75B" />
              <Text style={styles.businessHeroBadgeText} numberOfLines={1}>{t("safeLocked")}</Text>
            </View>
            <View style={styles.businessHeroBadge}>
              <View style={styles.sourceDot} />
              <Text style={styles.businessHeroBadgeText} numberOfLines={1}>{t("realOnly")}</Text>
            </View>
          </View>
          <Text style={styles.businessTitle} numberOfLines={1}>{t("businessStudio")}</Text>
          <Text style={styles.businessSubtitle} numberOfLines={2}>
            {t("liveCommerce")} · {t("noFakeOrders")} · {t("commerceLockedNoProvider")}
          </Text>
        </View>
        <View style={styles.businessHeroIcon}>
          <Ionicons name="briefcase-outline" size={34} color="#F2C75B" />
        </View>
      </LinearGradient>

      <View style={styles.businessSafetyBar}>
        <View style={styles.sourceDot} />
        <Text style={styles.businessSafetyText} numberOfLines={1}>
          {t("merchantProviderLater")} · {t("walletProviderLater")} · {t("noFakeBusinessPayment")}
        </Text>
      </View>

      <View style={styles.businessReadinessCard}>
        <View style={styles.businessReadinessTop}>
          <View>
            <Text style={styles.businessReadinessTitle}>{t("readiness")}</Text>
            <Text style={styles.businessReadinessMeta} numberOfLines={1}>{t("shoppingOnlyBusiness")} · {t("noBuyButtonBeforeProvider")}</Text>
          </View>
          <View style={styles.businessReadinessBadge}>
            <Text style={styles.businessReadinessBadgeText}>{t("providerNotConfigured")}</Text>
          </View>
        </View>
        <ScrollView
          horizontal
          showsHorizontalScrollIndicator={false}
          nestedScrollEnabled
          overScrollMode="never"
          contentContainerStyle={styles.businessSetupRail}
        >
          {businessSetupSteps.map((step) => (
            <View key={`${step.title}-${step.status}`} style={styles.businessSetupStep}>
              <View style={styles.businessSetupStepIcon}>
                <Ionicons name={step.icon} size={18} color="#F2C75B" />
              </View>
              <Text style={styles.businessSetupStepTitle} numberOfLines={1}>{t(step.title)}</Text>
              <Text style={styles.businessSetupStepStatus} numberOfLines={1}>{t(step.status)}</Text>
            </View>
          ))}
        </ScrollView>
      </View>

      <View style={styles.businessGrid}>
        {businessTiles.map((tile) => {
          const active = selectedBusinessAction === tile.action;
          return (
            <Pressable
              key={`${tile.title}-${tile.status}`}
              style={[styles.businessTile, active ? styles.businessTileActive : null]}
              onPress={() => setSelectedBusinessAction(tile.action)}
              hitSlop={{ top: 6, bottom: 6, left: 4, right: 4 }}
              accessibilityRole="button"
              accessibilityState={{ selected: active }}
              accessibilityLabel={`${t(tile.title)} · ${t(tile.status)}`}
            >
              <View style={[styles.businessTileIcon, active ? styles.businessTileIconActive : null]}>
                <Ionicons name={tile.icon} size={25} color={active ? "#09070D" : "#F2C75B"} />
              </View>
              <Text style={[styles.businessTileTitle, active ? styles.businessTileTitleActive : null]} numberOfLines={2}>{t(tile.title)}</Text>
              <Text style={[styles.businessTileStatus, active ? styles.businessTileStatusActive : null]} numberOfLines={2}>{t(tile.status)}</Text>
            </Pressable>
          );
        })}
      </View>

      <View style={styles.businessDetailCard}>
        <View style={styles.businessDetailIcon}>
          <Ionicons name={selectedBusinessTile.icon} size={26} color="#F2C75B" />
        </View>
        <View style={styles.businessDetailText}>
          <Text style={styles.businessDetailTitle} numberOfLines={1}>{t(selectedBusinessTile.title)}</Text>
          <Text style={styles.businessDetailMeta} numberOfLines={2}>
            {t(selectedBusinessTile.status)} · {t("draftOnly")} · {t("providerNotConfigured")}
          </Text>
        </View>
        <View style={styles.businessDetailLock}>
          <Ionicons name="lock-closed-outline" size={18} color="#09070D" />
        </View>
      </View>

      <View style={styles.businessProductPreviewCard}>
        <View style={styles.businessSectionTop}>
          <View>
            <Text style={styles.businessSectionTitle}>{t("businessProductShelf")}</Text>
            <Text style={styles.businessSectionMeta} numberOfLines={1}>{t("draftOnly")} · {t("productApprovalRequired")}</Text>
          </View>
          <View style={styles.businessSectionBadge}>
            <Ionicons name="lock-closed-outline" size={13} color="#F2C75B" />
            <Text style={styles.businessSectionBadgeText}>{t("safeLocked")}</Text>
          </View>
        </View>
        <ScrollView
          horizontal
          showsHorizontalScrollIndicator={false}
          nestedScrollEnabled
          overScrollMode="never"
          contentContainerStyle={styles.businessProductPreviewRail}
        >
          {businessProductPreviewCards.map((card) => (
            <View key={`${card.title}-${card.status}`} style={styles.businessProductPreviewTile}>
              <View style={styles.businessProductPreviewIcon}>
                <Ionicons name={card.icon} size={20} color="#F2C75B" />
              </View>
              <Text style={styles.businessProductPreviewTitle} numberOfLines={1}>{t(card.title)}</Text>
              <Text style={styles.businessProductPreviewMeta} numberOfLines={2}>{t(card.status)} · {t(card.gate)}</Text>
            </View>
          ))}
        </ScrollView>
      </View>

      <View style={styles.businessCheckoutLockCard}>
        <View style={styles.businessSectionTop}>
          <View>
            <Text style={styles.businessSectionTitle}>{t("walletCheckout")}</Text>
            <Text style={styles.businessSectionMeta} numberOfLines={1}>{t("noFakeBusinessPayment")} · {t("providerNotConfigured")}</Text>
          </View>
          <View style={styles.businessCheckoutLockIcon}>
            <Ionicons name="shield-checkmark-outline" size={20} color="#09070D" />
          </View>
        </View>
        <View style={styles.businessCheckoutSteps}>
          {businessCheckoutLockedSteps.map((step) => (
            <View key={`${step.title}-${step.status}`} style={styles.businessCheckoutStep}>
              <Ionicons name={step.icon} size={18} color="#F2C75B" />
              <View style={styles.businessCheckoutStepText}>
                <Text style={styles.businessCheckoutStepTitle} numberOfLines={1}>{t(step.title)}</Text>
                <Text style={styles.businessCheckoutStepMeta} numberOfLines={1}>{t(step.status)} · {t(step.gate)}</Text>
              </View>
            </View>
          ))}
        </View>
        <Pressable
          style={styles.businessCheckoutDisabledButton}
          disabled={true}
          accessibilityState={{ disabled: true }}
          accessibilityLabel={`${t("buyLocked")} · ${t("providerNotConfigured")}`}
        >
          <Text style={styles.businessCheckoutDisabledText}>{t("buyLocked")}</Text>
        </Pressable>
      </View>

      <View style={styles.businessVisualQaCard}>
        <View style={styles.businessVisualQaTop}>
          <View style={styles.businessVisualQaIcon}>
            <Ionicons name="phone-portrait-outline" size={20} color="#F2C75B" />
          </View>
          <View style={styles.businessVisualQaTitleWrap}>
            <Text style={styles.businessVisualQaTitle}>{t("readiness")}</Text>
            <Text style={styles.businessVisualQaMeta} numberOfLines={2}>
              {t("safeLocked")} · {t("providerNotConfigured")} · {t("noFakeBusinessPayment")}
            </Text>
          </View>
        </View>
        <View style={styles.businessVisualQaGrid}>
          {businessVisualQaSteps.map((step) => (
            <View key={`${step.title}-${step.status}-${step.gate}`} style={styles.businessVisualQaStep}>
              <View style={styles.businessVisualQaStepIcon}>
                <Ionicons name={step.icon} size={16} color="#F2C75B" />
              </View>
              <View style={styles.businessVisualQaStepText}>
                <Text style={styles.businessVisualQaStepTitle} numberOfLines={1}>{t(step.title)}</Text>
                <Text style={styles.businessVisualQaStepMeta} numberOfLines={1}>{t(step.status)} · {t(step.gate)}</Text>
              </View>
            </View>
          ))}
        </View>
      </View>
    </View>
  );
}

type CreatorTileAction = "setup" | "official" | "monetization" | "gifts" | "documents" | "analytics" | "rules" | "access";

type CreatorTile = {
  icon: IconName;
  title: StreamTextKey;
  status: StreamTextKey;
  action: CreatorTileAction;
};

const creatorTiles: CreatorTile[] = [
  { icon: "person-circle-outline", title: "streamerSetup", status: "notConnected", action: "setup" },
  { icon: "shield-checkmark-outline", title: "officialRegistration", status: "adminReviewLater", action: "official" },
  { icon: "cash-outline", title: "monetization", status: "monetizationLocked", action: "monetization" },
  { icon: "gift-outline", title: "gifts", status: "giftIncomeLocked", action: "gifts" },
  { icon: "document-text-outline", title: "documents", status: "verificationPending", action: "documents" },
  { icon: "analytics-outline", title: "analytics", status: "providerLater", action: "analytics" },
  { icon: "book-outline", title: "rules", status: "safeLocked", action: "rules" },
  { icon: "people-outline", title: "studioAccess", status: "notConnected", action: "access" },
];

type OfficialRegistrationStep = {
  icon: IconName;
  title: StreamTextKey;
  status: StreamTextKey;
  draftSupported: boolean;
};

const officialRegistrationSteps: OfficialRegistrationStep[] = [
  { icon: "person-outline", title: "creatorName", status: "requiredLater", draftSupported: true },
  { icon: "list-outline", title: "streamCategory", status: "requiredLater", draftSupported: true },
  { icon: "images-outline", title: "profileMedia", status: "providerNotConfigured", draftSupported: false },
  { icon: "id-card-outline", title: "identityCheck", status: "approvalLocked", draftSupported: false },
  { icon: "wallet-outline", title: "walletBinding", status: "providerNotConfigured", draftSupported: false },
  { icon: "book-outline", title: "creatorRulesAgree", status: "requiredLater", draftSupported: true },
];

type VerificationControlTile = {
  icon: IconName;
  title: StreamTextKey;
  status: StreamTextKey;
  draftSupported: boolean;
};

const verificationControlTiles: VerificationControlTile[] = [
  { icon: "finger-print-outline", title: "identityCheck", status: "identityProviderLater", draftSupported: false },
  { icon: "document-text-outline", title: "documentReview", status: "documentProviderLater", draftSupported: false },
  { icon: "grid-outline", title: "creatorCategory", status: "categoryProviderLater", draftSupported: true },
  { icon: "wallet-outline", title: "monetizationEligibility", status: "monetizationReviewLater", draftSupported: false },
  { icon: "ribbon-outline", title: "officialBadgeReview", status: "badgeProviderLater", draftSupported: false },
  { icon: "shield-checkmark-outline", title: "policyChecklist", status: "policyProviderLater", draftSupported: true },
  { icon: "checkmark-done-outline", title: "adminDecision", status: "adminReviewLater", draftSupported: false },
];

function StreamCreatorVerificationPanel({
  visible,
  onClose,
  t,
}: {
  visible: boolean;
  onClose: () => void;
  t: (key: StreamTextKey) => string;
}) {
  const [selectedVerificationDraft, setSelectedVerificationDraft] = useState<StreamTextKey | null>(null);

  useEffect(() => {
    setSelectedVerificationDraft(null);
  }, [visible]);

  const closeVerificationDraft = () => {
    setSelectedVerificationDraft(null);
    onClose();
  };

  const selectedVerificationTile = verificationControlTiles.find((tile) => tile.title === selectedVerificationDraft && tile.draftSupported) ?? null;
  const verificationDraftReady = selectedVerificationTile !== null;

  if (!visible) {
    return null;
  }

  return (
    <Modal visible={visible} transparent animationType="fade" onRequestClose={closeVerificationDraft}>
      <Pressable style={styles.modalBackdrop} onPress={closeVerificationDraft}>
        <Pressable style={styles.creatorVerificationSheet} onPressIn={(event) => event.stopPropagation()}
          onPress={(event) => event.stopPropagation()}>
          <View style={styles.creatorVerificationTop}>
            <View style={styles.creatorVerificationIcon}>
              <Ionicons name="shield-checkmark-outline" size={25} color="#F2C75B" />
            </View>
            <View style={styles.creatorVerificationTitleWrap}>
              <Text style={styles.creatorVerificationTitle} numberOfLines={1}>{t("creatorVerification")}</Text>
              <Text style={styles.creatorVerificationMeta} numberOfLines={1}>{verificationDraftReady ? `${t(selectedVerificationTile.title)} · черновик закрыт` : t("adminReviewLater")}</Text>
            </View>
            <Pressable style={styles.creatorModalClose} hitSlop={10} onPress={closeVerificationDraft} accessibilityRole="button" accessibilityLabel="Закрыть верификацию">
              <Ionicons name="close" size={22} color="#FFFFFF" />
            </Pressable>
          </View>

          <View style={[styles.creatorVerificationNotice, verificationDraftReady ? styles.creatorVerificationNoticeActive : null]} accessibilityState={{ selected: verificationDraftReady }}>
            <View style={styles.sourceDot} />
            <Text style={[styles.creatorVerificationNoticeText, verificationDraftReady ? styles.creatorVerificationNoticeTextActive : null]} numberOfLines={2}>
              {t("noFakeApproval")} · {t("noFakeVerification")} · {t("noFakeDocuments")} · {t("noFakeAdminDecision")} · {verificationDraftReady ? "локальный черновик" : t("noFakeOfficialBadge")}
            </Text>
          </View>

          <View style={[styles.creatorVerificationPreview, verificationDraftReady ? styles.creatorVerificationPreviewActive : null]} accessibilityState={{ selected: verificationDraftReady }}>
            <Ionicons name={selectedVerificationTile?.icon ?? "ribbon-outline"} size={44} color={verificationDraftReady ? "#09070D" : "#F2C75B"} />
            <Text style={[styles.creatorVerificationPreviewTitle, verificationDraftReady ? styles.creatorVerificationPreviewTitleActive : null]}>{selectedVerificationTile ? t(selectedVerificationTile.title) : t("officialBadgeReview")}</Text>
            <Text style={[styles.creatorVerificationPreviewMeta, verificationDraftReady ? styles.creatorVerificationPreviewMetaActive : null]}>{selectedVerificationTile ? `${t(selectedVerificationTile.status)} · локальный черновик` : t("verificationProviderLater")}</Text>
          </View>

          <View style={styles.creatorVerificationGrid}>
            {verificationControlTiles.map((tile) => {
              const locked = !tile.draftSupported;
              const active = !locked && selectedVerificationDraft === tile.title;
              return (
                <Pressable
                  key={`${tile.title}-${tile.status}`}
                  style={[styles.creatorVerificationTile, active ? styles.creatorVerificationTileActive : null, locked ? styles.creatorVerificationTileLocked : null]}
                  onPress={() => {
                    if (locked) {
                      return;
                    }
                    setSelectedVerificationDraft((current) => current === tile.title ? null : tile.title);
                  }}
                  disabled={locked}
                  accessibilityState={{ selected: active, disabled: locked }}
                  accessibilityLabel={`${t(tile.title)} · ${locked ? t("providerNotConfigured") : active ? "локальный черновик" : t(tile.status)}`}
                >
                  <View style={[styles.creatorVerificationTileIcon, active ? styles.creatorVerificationTileIconActive : null, locked ? styles.creatorVerificationTileIconLocked : null]}>
                    <Ionicons name={locked ? "lock-closed-outline" : tile.icon} size={21} color={active ? "#09070D" : locked ? "#8D8796" : "#F2C75B"} />
                  </View>
                  <View style={styles.creatorVerificationTileText}>
                    <Text style={[styles.creatorVerificationTileTitle, active ? styles.creatorVerificationTileTitleActive : null, locked ? styles.creatorVerificationTileTitleLocked : null]} numberOfLines={1}>{t(tile.title)}</Text>
                    <Text style={[styles.creatorVerificationTileStatus, active ? styles.creatorVerificationTileStatusActive : null, locked ? styles.creatorVerificationTileStatusLocked : null]} numberOfLines={1}>{locked ? `${t(tile.status)} · ${t("providerNotConfigured")}` : active ? `${t(tile.status)} · локальный черновик` : t(tile.status)}</Text>
                  </View>
                </Pressable>
              );
            })}
          </View>

          <Pressable
            style={[styles.creatorVerificationLockedButton, verificationDraftReady ? styles.creatorVerificationLockedButtonActive : null]}
            disabled={true}
            accessibilityState={{ selected: verificationDraftReady, disabled: true }}
            accessibilityLabel={verificationDraftReady ? `${t("submitVerificationLocked")} · черновик закрыт` : t("submitVerificationLocked")}
          >
            <Text style={[styles.creatorVerificationLockedText, verificationDraftReady ? styles.creatorVerificationLockedTextActive : null]}>{verificationDraftReady ? `${t("submitVerificationLocked")} · черновик` : t("submitVerificationLocked")}</Text>
          </Pressable>
        </Pressable>
      </Pressable>
    </Modal>
  );
}

function CreatorRegistrationModal({
  visible,
  tile,
  onClose,
  onOpenVerification,
  t,
}: {
  visible: boolean;
  tile: CreatorTile | null;
  onClose: () => void;
  onOpenVerification: () => void;
  t: (key: StreamTextKey) => string;
}) {
  const [selectedRegistrationDraft, setSelectedRegistrationDraft] = useState<StreamTextKey | null>(null);

  useEffect(() => {
    setSelectedRegistrationDraft(null);
  }, [visible, tile?.title, tile?.action]);

  const closeRegistrationDraft = () => {
    setSelectedRegistrationDraft(null);
    onClose();
  };

  if (!tile) {
    return null;
  }

  const showOfficialSteps = tile.action === "official" || tile.action === "setup" || tile.action === "documents";
  const selectedRegistrationStep = showOfficialSteps
    ? officialRegistrationSteps.find((step) => step.title === selectedRegistrationDraft && step.draftSupported) ?? null
    : null;
  const registrationDraftReady = selectedRegistrationStep !== null;
  const openVerificationDraft = () => {
    if (!registrationDraftReady) {
      return;
    }
    setSelectedRegistrationDraft(null);
    onOpenVerification();
  };

  return (
    <Modal visible={visible} transparent animationType="fade" onRequestClose={closeRegistrationDraft}>
      <Pressable style={styles.modalBackdrop} onPress={closeRegistrationDraft}>
        <Pressable style={styles.creatorModalSheet} onPressIn={(event) => event.stopPropagation()}
          onPress={(event) => event.stopPropagation()}>
          <View style={styles.creatorModalTop}>
            <View style={styles.creatorIconBox}>
              <Ionicons name={tile.icon} size={25} color="#F2C75B" />
            </View>
            <View style={styles.creatorModalTitleWrap}>
              <Text style={styles.creatorModalTitle} numberOfLines={1}>{t(tile.title)}</Text>
              <Text style={styles.creatorModalMeta} numberOfLines={1}>{t(tile.status)}</Text>
            </View>
            <Pressable style={styles.creatorModalClose} hitSlop={10} onPress={closeRegistrationDraft} accessibilityRole="button" accessibilityLabel="Закрыть регистрацию">
              <Ionicons name="close" size={22} color="#FFFFFF" />
            </Pressable>
          </View>

          <View style={[styles.creatorModalSafety, registrationDraftReady ? styles.creatorModalSafetyActive : null]} accessibilityState={{ selected: registrationDraftReady }}>
            <View style={styles.sourceDot} />
            <Text style={[styles.creatorModalSafetyText, registrationDraftReady ? styles.creatorModalSafetyTextActive : null]} numberOfLines={2}>
              {t("draftOnly")} · {t("noFakeApproval")} · {t("noFakeDocuments")} · {registrationDraftReady ? `${t(selectedRegistrationStep.title)} · локальный черновик` : t("reviewQueueLater")}
            </Text>
          </View>

          <View style={styles.registrationBlock}>
            <Text style={styles.settingLabel}>{t(showOfficialSteps ? "registrationForm" : tile.title)}</Text>

            {showOfficialSteps ? officialRegistrationSteps.map((step) => {
              const locked = !step.draftSupported;
              const active = !locked && selectedRegistrationDraft === step.title;
              return (
                <Pressable
                  key={step.title}
                  style={[styles.registrationStep, active ? styles.registrationStepActive : null, locked ? styles.registrationStepLocked : null]}
                  onPress={() => {
                    if (locked) {
                      return;
                    }
                    setSelectedRegistrationDraft((current) => current === step.title ? null : step.title);
                  }}
                  disabled={locked}
                  accessibilityState={{ selected: active, disabled: locked }}
                  accessibilityLabel={`${t(step.title)} · ${locked ? t("providerNotConfigured") : active ? "локальный черновик" : t(step.status)}`}
                >
                  <View style={[styles.registrationStepIcon, active ? styles.registrationStepIconActive : null, locked ? styles.registrationStepIconLocked : null]}>
                    <Ionicons name={locked ? "lock-closed-outline" : step.icon} size={20} color={active ? "#09070D" : locked ? "#8D8796" : "#F2C75B"} />
                  </View>
                  <View style={styles.registrationStepText}>
                    <Text style={[styles.registrationStepTitle, active ? styles.registrationStepTitleActive : null, locked ? styles.registrationStepTitleLocked : null]}>{t(step.title)}</Text>
                    <Text style={[styles.registrationStepStatus, active ? styles.registrationStepStatusActive : null, locked ? styles.registrationStepStatusLocked : null]}>{active ? `${t(step.status)} · локальный черновик` : locked ? `${t(step.status)} · ${t("providerNotConfigured")}` : t(step.status)}</Text>
                  </View>
                </Pressable>
              );
            }) : (
              <View style={[styles.registrationStep, styles.registrationStepLocked]} accessibilityState={{ disabled: true }}>
                <View style={styles.registrationStepIcon}>
                  <Ionicons name="lock-closed-outline" size={20} color="#F2C75B" />
                </View>
                <View style={styles.registrationStepText}>
                  <Text style={styles.registrationStepTitle}>{t("providerNotConfigured")}</Text>
                  <Text style={styles.registrationStepStatus}>{t("reviewQueueLater")}</Text>
                </View>
              </View>
            )}
          </View>

          <Pressable
            style={[styles.submitReviewButton, !registrationDraftReady ? styles.submitReviewButtonDisabled : styles.submitReviewButtonDraft]}
            onPress={openVerificationDraft}
            disabled={!registrationDraftReady}
            accessibilityState={{ selected: registrationDraftReady, disabled: !registrationDraftReady }}
            accessibilityLabel={registrationDraftReady ? `${t("creatorVerification")} · локальный черновик` : `${t("submitForReview")} · ${t("reviewQueueLater")}`}
          >
            <Text style={[styles.submitReviewText, !registrationDraftReady ? styles.submitReviewTextDisabled : styles.submitReviewTextDraft]}>
              {registrationDraftReady ? `${t("creatorVerification")} · черновик` : t("submitForReview")}
            </Text>
          </Pressable>
        </Pressable>
      </Pressable>
    </Modal>
  );
}

function isCreatorTileDraftSupported(action: CreatorTileAction): boolean {
  return action === "setup" || action === "official" || action === "documents";
}

function ProfileStatusPill({ t }: { t: (key: StreamTextKey) => string }) {
  return (
    <View style={styles.profileStatusPill}>
      <View style={styles.sourceDot} />
      <Text style={styles.profileStatusText} numberOfLines={1}>{t("verificationPending")}</Text>
    </View>
  );
}

function ProfileScreen({ t }: { t: (key: StreamTextKey) => string }) {
  const [selectedTile, setSelectedTile] = useState<CreatorTile | null>(null);
  const [verificationOpen, setVerificationOpen] = useState(false);

  return (
    <View style={styles.profile}>
      <View style={styles.profileHero}>
        <LinearGradient colors={["#191421", "#0C0A11"]} style={styles.profileHeroGradient}>
          <View style={styles.avatar} />
          <View style={styles.profileHeroText}>
            <Text style={styles.profileTitle} numberOfLines={1}>{t("creatorStudio")}</Text>
            <Text style={styles.profileSubtitle} numberOfLines={2}>{t("realDataOnly")} · {t("providerLater")}</Text>
          </View>
          <ProfileStatusPill t={t} />
        </LinearGradient>
      </View>

      <StreamProfileSetupPanel />

      <View style={styles.creatorGrid}>
        {creatorTiles.map((tile) => {
          const selected = selectedTile?.action === tile.action;
          const draftSupported = isCreatorTileDraftSupported(tile.action);
          const locked = !draftSupported;
          return (
            <Pressable
              key={`${tile.title}-${tile.status}`}
              style={[styles.creatorTile, selected && draftSupported ? styles.creatorTileActive : null, locked ? styles.creatorTileLocked : null]}
              onPress={() => {
                if (!draftSupported) {
                  return;
                }
                setSelectedTile(tile);
              }}
              disabled={locked}
              accessibilityState={{ selected: selected && draftSupported, disabled: locked }}
              accessibilityLabel={`${t(tile.title)} · ${locked ? t("providerNotConfigured") : t(tile.status)}`}
            >
              <View style={[styles.creatorIconBox, selected && draftSupported ? styles.creatorIconBoxActive : null, locked ? styles.creatorIconBoxLocked : null]}>
                <Ionicons name={tile.icon} size={25} color={selected && draftSupported ? "#09070D" : locked ? "#8D8796" : "#F2C75B"} />
              </View>
              <Text style={[styles.creatorTileTitle, selected && draftSupported ? styles.creatorTileTitleActive : null, locked ? styles.creatorTileTitleLocked : null]} numberOfLines={2}>{t(tile.title)}</Text>
              <Text style={[styles.creatorTileStatus, selected && draftSupported ? styles.creatorTileStatusActive : null, locked ? styles.creatorTileStatusLocked : null]} numberOfLines={2}>
                {locked ? `${t(tile.status)} · ${t("providerNotConfigured")}` : t(tile.status)}
              </Text>
            </Pressable>
          );
        })}
      </View>

      <StreamCreatorVerificationPanel
        visible={verificationOpen}
        onClose={() => setVerificationOpen(false)}
        t={t}
      />

      <CreatorRegistrationModal
        visible={Boolean(selectedTile)}
        tile={selectedTile}
        onClose={() => setSelectedTile(null)}
        onOpenVerification={() => {
          setSelectedTile(null);
          setVerificationOpen(true);
        }}
        t={t}
      />
    </View>
  );
}

export default function StreamScreen() {
  const insets = useSafeAreaInsets();
  const { height, width } = useWindowDimensions();
  const { language } = useI18n();
  const t = useMemo(() => createStreamTranslator(language), [language]);
  const [active, setActive] = useState<Tab>("home");

  const topLimit = Math.max(insets.top + 12, 32);
  const bottomTabBottom = Math.max(insets.bottom + 4, 8);
  const bottomLimit = bottomTabBottom + TAB_BAR_HEIGHT + 8;

  return (
    <View style={styles.container}>
      <StatusBar style="light" />
      {active === "home" ? (
        <HomeScreen t={t} topLimit={topLimit} bottomLimit={bottomLimit} screenHeight={height} screenWidth={width} language={language} onOpenTab={setActive} />
      ) : active === "live" ? (
        <View style={[styles.liveTabFrame, { paddingTop: topLimit, paddingBottom: bottomLimit }]}>
          <LiveSetupScreen t={t} language={language} />
        </View>
      ) : (
        <ScrollView
          showsVerticalScrollIndicator={false}
          keyboardShouldPersistTaps="handled"
          nestedScrollEnabled={true}
          overScrollMode="never"
          contentContainerStyle={[styles.scroll, { paddingTop: topLimit, paddingBottom: bottomLimit + 28 }]}
          scrollIndicatorInsets={{ top: topLimit, bottom: bottomLimit + 28 }}
        >
          {active === "business" ? <BusinessStreamScreen t={t} /> : null}
          {active === "shorts" ? <ShortsScreen t={t} /> : null}
          {active === "profile" ? <ProfileScreen t={t} /> : null}
        </ScrollView>
      )}
      <BottomTabs active={active} setActive={setActive} t={t} bottom={bottomTabBottom} screenWidth={width} />
    </View>
  );
}

